     1в†’/**
     2в†’ * Export Routes
     3в†’ *
     4в†’ * REST endpoints for exporting PM schedules (Excel/CSV) and generating reports (PDF).
     5в†’ * Uses async job processing with status polling.
     6в†’ *
     7в†’ * Key endpoints:
     8в†’ * - POST /export/pm-schedule - Queue PM schedule export
     9в†’ * - POST /export/report - Queue report generation
    10в†’ * - GET /export/:jobId - Get export job status and download URL
    11в†’ * - GET /export/jobs - List export jobs for current user
    12в†’ *
    13в†’ * @see specs/005-api.md Section 5.15
    14в†’ */
    15в†’
    16в†’import { Hono } from 'hono';
    17в†’import * as fs from 'node:fs';
    18в†’import * as path from 'node:path';
    19в†’import {
    20в†’  success,
    21в†’  paginatedSuccess,
    22в†’  error,
    23в†’  parsePaginationQuery,
    24в†’  ErrorCodes,
    25в†’  type AppVariables,
    26в†’} from '../types';
    27в†’import { getRequestId, getRequestDuration } from '../middleware/request-context';
    28в†’import {
    29в†’  getExportService,
    30в†’  type PmScheduleExportRequest,
    31в†’  type ReportExportRequest,
    32в†’  type ExportJobStatus,
    33в†’  type ReportType,
    34в†’} from '../../services/export';
    35в†’import { SYSTEM_USER_ID } from '../../lib/constants';
    36в†’
    37в†’// Reports output directory
    38в†’const REPORTS_OUTPUT_DIR = process.env['REPORTS_OUTPUT_DIR'] ?? '/tmp/mms-reports';
    39в†’
    40в†’// MIME type mapping for export files
    41в†’const MIME_TYPES: Record<string, string> = {
    42в†’  '.pdf': 'application/pdf',
    43в†’  '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    44в†’  '.csv': 'text/csv',
    45в†’};
    46в†’
    47в†’// Singleton service instance
    48в†’let exportService: ReturnType<typeof getExportService> | null = null;
    49в†’
    50в†’function getService(): ReturnType<typeof getExportService> {
    51в†’  if (!exportService) {
    52в†’    exportService = getExportService();
    53в†’  }
    54в†’  return exportService;
    55в†’}
    56в†’
    57в†’export const exportRoutes = new Hono<{ Variables: AppVariables }>();
    58в†’
    59в†’/**
    60в†’ * POST /export/pm-schedule
    61в†’ *
    62в†’ * Queue a PM schedule export job.
    63в†’ *
    64в†’ * Request Body:
    65в†’ * - format: Export format ('xlsx' or 'csv')
    66в†’ * - filters: Optional filters (depotId, fleetId, trainId, fromDate, toDate, status, pmTypeId, scenarioId)
    67в†’ * - columns: Optional list of columns to include
    68в†’ *
    69в†’ * Returns 202 Accepted with job ID for polling.
    70в†’ */
    71в†’exportRoutes.post('/export/pm-schedule', async (c) => {
    72в†’  const requestId = getRequestId(c);
    73в†’  const service = getService();
    74в†’
    75в†’  try {
    76в†’    const body = await c.req.json();
    77в†’
    78в†’    // Validate required fields
    79в†’    if (!body.format) {
    80в†’      return c.json(
    81в†’        error(ErrorCodes.VALIDATION_ERROR, 'format is required', requestId, {
    82в†’          field: 'format',
    83в†’          expected: ['xlsx', 'csv'],
    84в†’        }),
    85в†’        400
    86в†’      );
    87в†’    }
    88в†’
    89в†’    if (!['xlsx', 'csv'].includes(body.format)) {
    90в†’      return c.json(
    91в†’        error(ErrorCodes.VALIDATION_ERROR, 'Invalid format', requestId, {
    92в†’          field: 'format',
    93в†’          expected: ['xlsx', 'csv'],
    94в†’          received: body.format,
    95в†’        }),
    96в†’        400
    97в†’      );
    98в†’    }
    99в†’
   100в†’    // Get user from context (or use default for now)
   101в†’    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   102в†’
   103в†’    const request: PmScheduleExportRequest = {
   104в†’      format: body.format,
   105в†’      filters: body.filters,
   106в†’      columns: body.columns,
   107в†’      requestedBy: userId,
   108в†’    };
   109в†’
   110в†’    const result = await service.queuePmScheduleExport(request);
   111в†’
   112в†’    return c.json(
   113в†’      success(
   114в†’        {
   115в†’          jobId: result.jobId,
   116в†’          status: result.status,
   117в†’          estimatedSizeBytes: result.estimatedSizeBytes,
   118в†’        },
   119в†’        { timing: { durationMs: getRequestDuration(c) } }
   120в†’      ),
   121в†’      202
   122в†’    );
   123в†’  } catch (err) {
   124в†’    const message = err instanceof Error ? err.message : 'Failed to queue export';
   125в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   126в†’  }
   127в†’});
   128в†’
   129в†’/**
   130в†’ * POST /export/report
   131в†’ *
   132в†’ * Queue a report generation job.
   133в†’ *
   134в†’ * Request Body:
   135в†’ * - reportType: Type of report to generate
   136в†’ * - parameters: Report-specific parameters
   137в†’ *
   138в†’ * Report Types:
   139в†’ * - WEEKLY_COMPLIANCE: Weekly PM compliance summary
   140в†’ * - MONTHLY_SUMMARY: Monthly fleet maintenance summary
   141в†’ * - FLEET_STATUS: Current fleet status report
   142в†’ * - DRIFT_REPORT: Baseline drift analysis
   143в†’ * - TCO_PROJECTION: Total cost of ownership projection
   144в†’ * - BOW_WAVE_ANALYSIS: Maintenance clustering analysis
   145в†’ * - MANHOUR_UTILIZATION: Man-hour utilization report
   146в†’ *
   147в†’ * Returns 202 Accepted with job ID for polling.
   148в†’ */
   149в†’exportRoutes.post('/export/report', async (c) => {
   150в†’  const requestId = getRequestId(c);
   151в†’  const service = getService();
   152в†’
   153в†’  try {
   154в†’    const body = await c.req.json();
   155в†’
   156в†’    // Validate required fields
   157в†’    if (!body.reportType) {
   158в†’      return c.json(
   159в†’        error(ErrorCodes.VALIDATION_ERROR, 'reportType is required', requestId, {
   160в†’          field: 'reportType',
   161в†’        }),
   162в†’        400
   163в†’      );
   164в†’    }
   165в†’
   166в†’    const validTypes: ReportType[] = [
   167в†’      'WEEKLY_COMPLIANCE',
   168в†’      'MONTHLY_SUMMARY',
   169в†’      'FLEET_STATUS',
   170в†’      'DRIFT_REPORT',
   171в†’      'TCO_PROJECTION',
   172в†’      'BOW_WAVE_ANALYSIS',
   173в†’      'MANHOUR_UTILIZATION',
   174в†’    ];
   175в†’
   176в†’    if (!validTypes.includes(body.reportType)) {
   177в†’      return c.json(
   178в†’        error(ErrorCodes.VALIDATION_ERROR, 'Invalid reportType', requestId, {
   179в†’          field: 'reportType',
   180в†’          expected: validTypes,
   181в†’          received: body.reportType,
   182в†’        }),
   183в†’        400
   184в†’      );
   185в†’    }
   186в†’
   187в†’    // Get user from context (or use default for now)
   188в†’    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   189в†’
   190в†’    const request: ReportExportRequest = {
   191в†’      reportType: body.reportType,
   192в†’      parameters: body.parameters ?? {},
   193в†’      requestedBy: userId,
   194в†’    };
   195в†’
   196в†’    const result = await service.queueReportExport(request);
   197в†’
   198в†’    return c.json(
   199в†’      success(
   200в†’        {
   201в†’          jobId: result.jobId,
   202в†’          status: result.status,
   203в†’          estimatedSizeBytes: result.estimatedSizeBytes,
   204в†’        },
   205в†’        { timing: { durationMs: getRequestDuration(c) } }
   206в†’      ),
   207в†’      202
   208в†’    );
   209в†’  } catch (err) {
   210в†’    const message = err instanceof Error ? err.message : 'Failed to queue report';
   211в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   212в†’  }
   213в†’});
   214в†’
   215в†’/**
   216в†’ * GET /export/jobs
   217в†’ *
   218в†’ * List export jobs for the current user.
   219в†’ * NOTE: This route MUST be defined before /export/:jobId to avoid route collision.
   220в†’ *
   221в†’ * Query Parameters:
   222в†’ * - page: Page number (default: 1)
   223в†’ * - pageSize: Items per page (default: 20, max: 100)
   224в†’ * - status: Filter by status (comma-separated: QUEUED,PROCESSING,COMPLETED,FAILED,EXPIRED)
   225в†’ * - type: Filter by type (pm_schedule or report)
   226в†’ */
   227в†’exportRoutes.get('/export/jobs', async (c) => {
   228в†’  const requestId = getRequestId(c);
   229в†’  const service = getService();
   230в†’
   231в†’  try {
   232в†’    // Get user from context (or use default for now)
   233в†’    const userId = c.get('user')?.id ?? SYSTEM_USER_ID;
   234в†’
   235в†’    // Parse query parameters
   236в†’    const pagination = parsePaginationQuery({
   237в†’      page: c.req.query('page') ? Number(c.req.query('page')) : undefined,
   238в†’      pageSize: c.req.query('pageSize') ? Number(c.req.query('pageSize')) : undefined,
   239в†’    });
   240в†’
   241в†’    // Parse status filter
   242в†’    let statusFilter: ExportJobStatus[] | undefined;
   243в†’    const statusParam = c.req.query('status');
   244в†’    if (statusParam) {
   245в†’      statusFilter = statusParam.split(',') as ExportJobStatus[];
   246в†’    }
   247в†’
   248в†’    // Parse type filter
   249в†’    const typeParam = c.req.query('type');
   250в†’    const typeFilter = typeParam === 'pm_schedule' || typeParam === 'report' ? typeParam : undefined;
   251в†’
   252в†’    const result = service.listExportJobs(userId, {
   253в†’      page: pagination.page,
   254в†’      pageSize: pagination.pageSize,
   255в†’      status: statusFilter,
   256в†’      type: typeFilter,
   257в†’    });
   258в†’
   259в†’    // Transform jobs to API response format
   260в†’    const jobs = result.jobs.map((job) => ({
   261в†’      jobId: job.id,
   262в†’      type: job.type,
   263в†’      status: job.status,
   264в†’      format: job.format,
   265в†’      createdAt: job.createdAt.toISOString(),
   266в†’      ...(job.completedAt && { completedAt: job.completedAt.toISOString() }),
   267в†’      ...(job.downloadUrl && { downloadUrl: job.downloadUrl }),
   268в†’      ...(job.expiresAt && { expiresAt: job.expiresAt.toISOString() }),
   269в†’      ...(job.fileSizeBytes && { fileSizeBytes: job.fileSizeBytes }),
   270в†’      ...(job.reportType && { reportType: job.reportType }),
   271в†’    }));
   272в†’
   273в†’    return c.json(
   274в†’      paginatedSuccess(jobs, {
   275в†’        page: pagination.page,
   276в†’        pageSize: pagination.pageSize,
   277в†’        totalItems: result.total,
   278в†’      }),
   279в†’      200
   280в†’    );
   281в†’  } catch (err) {
   282в†’    const message = err instanceof Error ? err.message : 'Failed to list export jobs';
   283в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   284в†’  }
   285в†’});
   286в†’
   287в†’/**
   288в†’ * GET /export/:jobId
   289в†’ *
   290в†’ * Get export job status and download URL.
   291в†’ *
   292в†’ * Path Parameters:
   293в†’ * - jobId: Export job ID
   294в†’ *
   295в†’ * Response includes:
   296в†’ * - jobId: Job identifier
   297в†’ * - status: Current status (QUEUED, PROCESSING, COMPLETED, FAILED, EXPIRED)
   298в†’ * - downloadUrl: URL to download file (only when COMPLETED)
   299в†’ * - expiresAt: When the download URL expires
   300в†’ * - fileSizeBytes: Actual file size (only when COMPLETED)
   301в†’ * - errorMessage: Error details (only when FAILED)
   302в†’ */
   303в†’exportRoutes.get('/export/:jobId', async (c) => {
   304в†’  const requestId = getRequestId(c);
   305в†’  const service = getService();
   306в†’
   307в†’  try {
   308в†’    const jobId = c.req.param('jobId');
   309в†’
   310в†’    if (!jobId) {
   311в†’      return c.json(
   312в†’        error(ErrorCodes.VALIDATION_ERROR, 'jobId is required', requestId),
   313в†’        400
   314в†’      );
   315в†’    }
   316в†’
   317в†’    const result = await service.getExportJobStatus(jobId);
   318в†’
   319в†’    return c.json(
   320в†’      success(
   321в†’        {
   322в†’          jobId: result.jobId,
   323в†’          status: result.status,
   324в†’          ...(result.downloadUrl && { downloadUrl: result.downloadUrl }),
   325в†’          ...(result.expiresAt && { expiresAt: result.expiresAt }),
   326в†’          ...(result.fileSizeBytes && { fileSizeBytes: result.fileSizeBytes }),
   327в†’          ...(result.errorMessage && { errorMessage: result.errorMessage }),
   328в†’          ...(result.progress !== undefined && { progress: result.progress }),
   329в†’        },
   330в†’        { timing: { durationMs: getRequestDuration(c) } }
   331в†’      ),
   332в†’      200
   333в†’    );
   334в†’  } catch (err) {
   335в†’    if (err instanceof Error && err.message.includes('not found')) {
   336в†’      return c.json(
   337в†’        error(ErrorCodes.NOT_FOUND, 'Export job not found', requestId, {
   338в†’          jobId: c.req.param('jobId'),
   339в†’        }),
   340в†’        404
   341в†’      );
   342в†’    }
   343в†’
   344в†’    const message = err instanceof Error ? err.message : 'Failed to get job status';
   345в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   346в†’  }
   347в†’});
   348в†’
   349в†’/**
   350в†’ * POST /export/cleanup
   351в†’ *
   352в†’ * Trigger cleanup of expired export jobs.
   353в†’ * Admin-only endpoint.
   354в†’ */
   355в†’exportRoutes.post('/export/cleanup', async (c) => {
   356в†’  const requestId = getRequestId(c);
   357в†’  const service = getService();
   358в†’
   359в†’  try {
   360в†’    const cleanedCount = service.cleanupExpiredExports();
   361в†’
   362в†’    return c.json(
   363в†’      success(
   364в†’        {
   365в†’          message: 'Cleanup completed',
   366в†’          cleanedCount,
   367в†’        },
   368в†’        { timing: { durationMs: getRequestDuration(c) } }
   369в†’      ),
   370в†’      200
   371в†’    );
   372в†’  } catch (err) {
   373в†’    const message = err instanceof Error ? err.message : 'Failed to cleanup exports';
   374в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   375в†’  }
   376в†’});
   377в†’
   378в†’/**
   379в†’ * GET /export/download/:filename
   380в†’ *
   381в†’ * Download a generated export file.
   382в†’ *
   383в†’ * Path Parameters:
   384в†’ * - filename: Name of the file to download
   385в†’ *
   386в†’ * Security:
   387в†’ * - Validates filename to prevent path traversal attacks
   388в†’ * - Only serves files from the configured reports directory
   389в†’ *
   390в†’ * @returns Binary file stream with appropriate Content-Type header
   391в†’ */
   392в†’exportRoutes.get('/export/download/:filename', async (c) => {
   393в†’  const requestId = getRequestId(c);
   394в†’  const filename = c.req.param('filename');
   395в†’
   396в†’  // Validate filename format - must be alphanumeric with limited special chars
   397в†’  if (!filename || !/^[a-zA-Z0-9_-]+\.(pdf|xlsx|csv)$/.test(filename)) {
   398в†’    return c.json(
   399в†’      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename format', requestId, {
   400в†’        pattern: '^[a-zA-Z0-9_-]+\\.(pdf|xlsx|csv)$',
   401в†’      }),
   402в†’      400
   403в†’    );
   404в†’  }
   405в†’
   406в†’  // Prevent path traversal
   407в†’  const safeName = path.basename(filename);
   408в†’  const filePath = path.join(REPORTS_OUTPUT_DIR, safeName);
   409в†’
   410в†’  // Verify the resolved path is within the allowed directory
   411в†’  const resolvedPath = path.resolve(filePath);
   412в†’  const resolvedDir = path.resolve(REPORTS_OUTPUT_DIR);
   413в†’  if (!resolvedPath.startsWith(resolvedDir)) {
   414в†’    return c.json(
   415в†’      error(ErrorCodes.VALIDATION_ERROR, 'Invalid filename', requestId),
   416в†’      400
   417в†’    );
   418в†’  }
   419в†’
   420в†’  try {
   421в†’    // Check if file exists
   422в†’    const stats = await fs.promises.stat(filePath);
   423в†’    if (!stats.isFile()) {
   424в†’      return c.json(
   425в†’        error(ErrorCodes.NOT_FOUND, 'File not found', requestId),
   426в†’        404
   427в†’      );
   428в†’    }
   429в†’
   430в†’    // Determine content type
   431в†’    const ext = path.extname(safeName).toLowerCase();
   432в†’    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
   433в†’
   434в†’    // Read file and stream response
   435в†’    const fileBuffer = await fs.promises.readFile(filePath);
   436в†’
   437в†’    // Set headers
   438в†’    c.header('Content-Type', contentType);
   439в†’    c.header('Content-Length', stats.size.toString());
   440в†’    c.header('Content-Disposition', `attachment; filename="${safeName}"`);
   441в†’    c.header('Cache-Control', 'private, max-age=3600');
   442в†’
   443в†’    return c.body(fileBuffer);
   444в†’  } catch (err) {
   445в†’    if (err && typeof err === 'object' && 'code' in err && err.code === 'ENOENT') {
   446в†’      return c.json(
   447в†’        error(ErrorCodes.NOT_FOUND, 'File not found', requestId, { filename: safeName }),
   448в†’        404
   449в†’      );
   450в†’    }
   451в†’
   452в†’    const message = err instanceof Error ? err.message : 'Failed to download file';
   453в†’    return c.json(error(ErrorCodes.INTERNAL_ERROR, message, requestId), 500);
   454в†’  }
   455в†’});
